const jwt = require('jsonwebtoken');
const config = require('./config'); // assuming your secret key is stored in a separate file

module.exports = async (req, res, next) => {
  const token = req.header('Authorization');

  if (!token) return res.status(401).send({ error: 'No authorization header found' });

  try {
    const decoded = jwt.verify(token, config.secretKey);
    req.user = decoded;
    next();
  } catch (error) {
    console.error(error);
    res.status(403).send({ error: 'Invalid token' });
  }
};